import React, { useState } from 'react';

const Dashboard = () => {
  const [syllabus, setSyllabus] = useState("");
  const [schedule, setSchedule] = useState([]);

  const generateSchedule = async () => {
    // Logic to call your AI backend route
    console.log("Generating schedule for:", syllabus);
  };

  return (
    <div className="dashboard">
      <h1>StudyPulse Planner</h1>
      <textarea 
        placeholder="Paste your syllabus here..." 
        onChange={(e) => setSyllabus(e.target.value)}
      />
      <button onClick={generateSchedule}>Generate AI Schedule</button>

      <div className="task-grid">
        {/* Map through generated schedule here */}
        <div className="task-card">
          <h3>Sample Task: Integration Basics</h3>
          <progress value="50" max="100"></progress>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
